"use client";

import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { createTrip } from "@/lib/actions/create-trip";
import { cn } from "@/lib/utils";
import { UploadButton } from "@/lib/upload-thing";
import { useState, useTransition } from "react";
import { useRouter } from "next/navigation";
import { Globe, Lock, X, MapPin } from "lucide-react";
import TripLocationForm from "@/components/ui/trip-location-form";
import { Location as PrismaLocation } from "@/app/generated/prisma/client";

// Тип для локации без полей БД
type NewLocation = Omit<PrismaLocation, 'id' | 'createdAt' | 'tripId'> & {
  id?: string;
};

// Тип для данных формы - переименовал чтобы не конфликтовать с встроенным FormData
interface TripFormData {
  title: string;
  description: string;
  startDate: string;
  endDate: string;
}

export default function NewTrip() {
  const router = useRouter();
  const [isPending, startTransition] = useTransition();
  
  // Состояния для всех полей формы
  const [formData, setFormData] = useState<TripFormData>({
    title: "",
    description: "",
    startDate: "",
    endDate: "",
  });
  
  const [mainImage, setMainImage] = useState<string | null>(null);
  const [additionalImages, setAdditionalImages] = useState<string[]>([]);
  const [locations, setLocations] = useState<NewLocation[]>([]);
  const [isPublic, setIsPublic] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [showError, setShowError] = useState(false);
  const [errorMessage, setErrorMessage] = useState("");
  const [currentStep, setCurrentStep] = useState(1);

  const showSuccessModal = () => {
    setShowSuccess(true);
    setTimeout(() => {
      router.push("/trips");
      router.refresh();
    }, 2000);
  };

  const showErrorModal = (message: string) => {
    setErrorMessage(message);
    setShowError(true);
    setTimeout(() => {
      setShowError(false);
    }, 3000);
  };

  const removeAdditionalImage = (index: number) => {
    setAdditionalImages(prev => prev.filter((_, i) => i !== index));
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    
    if (!mainImage) {
      showErrorModal("Пожалуйста, загрузите главное изображение тура");
      return;
    }
    
    // Создаем новый FormData и добавляем все данные
    const submitData = new FormData();
    submitData.append("title", formData.title);
    submitData.append("description", formData.description);
    submitData.append("startDate", formData.startDate);
    submitData.append("endDate", formData.endDate);
    submitData.append("mainImage", mainImage);
    submitData.append("additionalImages", JSON.stringify(additionalImages));
    submitData.append("locations", JSON.stringify(locations));
    submitData.append("isPublic", String(isPublic));
    
    startTransition(async () => {
      const result = await createTrip(submitData);
      
      if (result.success) {
        showSuccessModal();
        // Сбрасываем все состояния
        setFormData({ title: "", description: "", startDate: "", endDate: "" });
        setMainImage(null);
        setAdditionalImages([]);
        setLocations([]);
        setIsPublic(false);
        setCurrentStep(1);
      } else {
        showErrorModal(result.error || "Ошибка при создании тура");
      }
    });
  };

  return (
    <>
      {/* Модальные окна */}
      {showSuccess && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-2xl p-12 max-w-md w-full mx-4 shadow-2xl animate-scale-in">
            <div className="text-center">
              <div className="mx-auto w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mb-6 animate-bounce-in">
                <svg className="w-12 h-12 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                </svg>
              </div>
              
              <h2 className="text-3xl font-bold text-gray-900 mb-3">
                Отлично!
              </h2>
              
              <p className="text-lg text-gray-600 mb-6">
                Тур успешно создан
              </p>
              
              <div className="flex items-center justify-center gap-2 text-sm text-gray-500">
                <svg className="animate-spin h-4 w-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                <span>Перенаправление на список туров...</span>
              </div>
            </div>
          </div>
        </div>
      )}

      {showError && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-2xl p-12 max-w-md w-full mx-4 shadow-2xl animate-scale-in">
            <div className="text-center">
              <div className="mx-auto w-20 h-20 bg-red-100 rounded-full flex items-center justify-center mb-6">
                <svg className="w-12 h-12 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </div>
              
              <h2 className="text-3xl font-bold text-gray-900 mb-3">
                Ошибка
              </h2>
              
              <p className="text-lg text-gray-600">
                {errorMessage}
              </p>
            </div>
          </div>
        </div>
      )}

      <div className="max-w-2xl mx-auto mt-10 pb-10">
        <Card>
          <CardHeader className="text-2xl font-bold">
            Создать новый тур
            <div className="flex gap-2 mt-4">
              <button
                type="button"
                onClick={() => setCurrentStep(1)}
                className={`flex-1 py-2 rounded-lg text-sm font-medium transition ${
                  currentStep === 1 
                    ? 'bg-gray-900 text-white' 
                    : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                }`}
              >
                1. Основная информация
              </button>
              <button
                type="button"
                onClick={() => setCurrentStep(2)}
                className={`flex-1 py-2 rounded-lg text-sm font-medium transition ${
                  currentStep === 2 
                    ? 'bg-gray-900 text-white' 
                    : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                }`}
              >
                2. Добавить места {locations.length > 0 && `(${locations.length})`}
              </button>
            </div>
          </CardHeader>
          <CardContent>
            <form
              className="space-y-6"
              onSubmit={handleSubmit}
            >
              {/* Шаг 1: Основная информация */}
              {currentStep === 1 && (
                <div className="space-y-6">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Название тура *</label>
                    <input 
                      type="text" 
                      name="title" 
                      value={formData.title}
                      onChange={handleInputChange}
                      placeholder="Например: Брестская крепость и окрестности" 
                      className={cn(
                        "w-full border border-gray-300 px-3 py-2",
                        "rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                      )} 
                      required 
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Описание *</label>
                    <textarea 
                      name="description" 
                      value={formData.description}
                      onChange={handleInputChange}
                      placeholder="Опишите маршрут, достопримечательности и особенности тура..." 
                      rows={4} 
                      className={cn(
                        "w-full border border-gray-300 px-3 py-2",
                        "rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 resize-none"
                      )} 
                      required 
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Дата начала</label>
                      <input 
                        type="date" 
                        name="startDate" 
                        value={formData.startDate}
                        onChange={handleInputChange}
                        className={cn(
                          "w-full border border-gray-300 px-3 py-2",
                          "rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                        )} 
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Дата окончания</label>
                      <input 
                        type="date" 
                        name="endDate" 
                        value={formData.endDate}
                        onChange={handleInputChange}
                        className={cn(
                          "w-full border border-gray-300 px-3 py-2",
                          "rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                        )} 
                      />
                    </div>
                  </div>

                  {/* Главное изображение */}
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Главное изображение *</label>
                    
                    {mainImage ? (
                      <div className="relative group mb-4">
                        <img 
                          src={mainImage} 
                          alt="Main" 
                          className="w-full rounded-md max-h-64 object-cover border border-gray-200"
                          onError={(e) => {
                            console.error("Ошибка загрузки изображения:", mainImage);
                            e.currentTarget.src = "https://via.placeholder.com/600x400?text=Ошибка+загрузки";
                          }}
                        />
                        <button
                          type="button"
                          onClick={() => setMainImage(null)}
                          className="absolute top-2 right-2 bg-red-500 text-white p-2 rounded-full hover:bg-red-600 transition shadow-lg opacity-0 group-hover:opacity-100"
                        >
                          <X className="w-4 h-4" />
                        </button>
                      </div>
                    ) : (
                      <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center hover:border-blue-500 transition-colors bg-gray-50">
                        <UploadButton
                          endpoint="imageUploader"
                          onClientUploadComplete={(res) => {
                            console.log("✅ Upload успешен:", res);
                            if (res && res[0]?.url) {
                              console.log("📸 URL изображения:", res[0].url);
                              setMainImage(res[0].url);
                            }
                          }}
                          onUploadError={(error: Error) => {
                            console.error("❌ Ошибка загрузки:", error);
                            showErrorModal("Ошибка при загрузке изображения");
                          }}
                        />
                      </div>
                    )}
                  </div>

                  {/* Дополнительные изображения */}
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Дополнительные фото (до 5 шт., необязательно)
                    </label>
                    
                    {additionalImages.length > 0 && (
                      <div className="grid grid-cols-3 gap-2 mb-4">
                        {additionalImages.map((url, index) => (
                          <div key={index} className="relative group aspect-square">
                            <img
                              src={url}
                              alt={`Additional ${index + 1}`}
                              className="w-full h-full object-cover rounded-md border border-gray-200"
                              onError={(e) => {
                                e.currentTarget.src = "/placeholder-image.svg";
                              }}
                            />
                            <button
                              type="button"
                              onClick={() => removeAdditionalImage(index)}
                              className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full hover:bg-red-600 transition opacity-0 group-hover:opacity-100"
                            >
                              <X className="w-3 h-3" />
                            </button>
                          </div>
                        ))}
                      </div>
                    )}
                    
                    {additionalImages.length < 5 && (
                      <div className="border-2 border-dashed border-gray-300 rounded-lg p-4 text-center hover:border-blue-500 transition-colors bg-gray-50">
                        <UploadButton
                          endpoint="imageUploader"
                          onClientUploadComplete={(res) => {
                            console.log("✅ Доп. фото загружено:", res);
                            if (res && res[0]?.url) {
                              setAdditionalImages(prev => [...prev, res[0].url]);
                            }
                          }}
                          onUploadError={(error: Error) => {
                            console.error("❌ Ошибка загрузки доп. фото:", error);
                            showErrorModal("Ошибка при загрузке изображения");
                          }}
                        />
                      </div>
                    )}
                  </div>

                  {/* Настройки публичности */}
                  <div className="p-4 bg-gray-50 rounded-xl">
                    <label className="flex items-center justify-between cursor-pointer">
                      <div className="flex items-center gap-3">
                        {isPublic ? (
                          <Globe className="w-5 h-5 text-green-600" />
                        ) : (
                          <Lock className="w-5 h-5 text-gray-400" />
                        )}
                        <div>
                          <p className="font-medium text-gray-900">
                            {isPublic ? "Публичный тур" : "Приватный тур"}
                          </p>
                          <p className="text-sm text-gray-500">
                            {isPublic 
                              ? "Ваш тур увидят другие пользователи" 
                              : "Только вы сможете видеть этот тур"}
                          </p>
                        </div>
                      </div>
                      <button
                        type="button"
                        onClick={() => setIsPublic(!isPublic)}
                        className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                          isPublic ? 'bg-green-600' : 'bg-gray-300'
                        }`}
                      >
                        <span
                          className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                            isPublic ? 'translate-x-6' : 'translate-x-1'
                          }`}
                        />
                      </button>
                    </label>
                  </div>

                  <Button 
                    type="button"
                    onClick={() => setCurrentStep(2)}
                    className="w-full"
                    disabled={!mainImage || !formData.title || !formData.description}
                  >
                    Далее: добавить места
                  </Button>
                </div>
              )}

              {/* Шаг 2: Добавление мест */}
              {currentStep === 2 && (
                <div className="space-y-6">
                  <div className="bg-blue-50 p-4 rounded-lg">
                    <div className="flex items-center gap-2 text-blue-800 mb-2">
                      <MapPin className="w-5 h-5" />
                      <h3 className="font-semibold">Добавьте места в маршрут</h3>
                    </div>
                    <p className="text-sm text-blue-600">
                      Вы можете добавить места сейчас или сделать это позже на странице тура.
                    </p>
                  </div>

                  <TripLocationForm 
                    onLocationsChange={setLocations}
                    initialLocations={locations}
                  />

                  <div className="flex gap-4 pt-4">
                    <Button 
                      type="button"
                      variant="outline"
                      onClick={() => setCurrentStep(1)}
                      className="flex-1"
                    >
                      Назад
                    </Button>
                    <Button 
                      type="submit"
                      disabled={isPending || !mainImage}
                      className="flex-1"
                    >
                      {isPending ? "Создание..." : "Создать тур"}
                      {locations.length > 0 && ` (${locations.length} мест)`}
                    </Button>
                  </div>
                </div>
              )}
            </form>
          </CardContent>
        </Card>
      </div>
    </>
  );
}